typedef struct { char name[64]; int status; int priority; } Item;

void setup_item(Item* it, const char* name, int prio) {
    strncpy(it->name, name, sizeof(it->name) - 1);
    it->name[sizeof(it->name) - 1] = '\0';
    it->status = 1;
    it->priority = prio;
}

